model.metadata:
CREATE VIEW v_penduduk AS
  SELECT nik, nama, tanggal_lahir, pekerjaan, penghasilan
  FROM bansos_db.master_penduduk;

CREATE VIEW v_penerima AS
  SELECT penerima_id, nik, nama_penerima
  FROM bansos_db.master_penerima;

CREATE VIEW v_penduduk_detail AS
  SELECT nik, nama, kode_pos
  FROM bansos_db.master_penduduk;
